#include<bits/stdc++.h>
#define fr front()
#define ba back()
#define pb push_back
#define pf push_front
#define ob pop_back()
#define of pop_front()
#define em empty()
using namespace std;
char str[300010];
int dp[300010],s[300010];
int main()
{
    int n,k;
    scanf("%d%d%s",&n,&k,str+1);
    for(int i=1;i<=n;i++)
    {
        s[i]=s[i-1]+(str[i]=='H'?-1:1);
    }
    memset(dp,0x3f,sizeof(dp));
    dp[0]=0;
    deque<int> q;
    q.pb(0);
    for(int i=1;i<=n;i++)
    {
        while(!q.em&&q.fr<i-k)
        {
            q.of;
        }
        dp[i]=dp[q.fr]+(s[i]-s[q.fr]>=0);
        while(!q.em&&(dp[i]<dp[q.ba]||(dp[i]==dp[q.ba]&&s[i]-s[q.ba]>=0)))
        {
            q.ob;
        }
        q.pb(i);
    }
    printf("%d",dp[n]);
    return 0;
}
